    int sum = calculateSum(numbers);
    double average = calculateAverage(numbers, sum);
    int max = findMax(numbers);
    int min = findMin(numbers);

    printStatistics(sum, average, max, min);
}

private int calculateSum(List<Integer> numbers) {
    int sum = 0;
    for (int number : numbers) {
        sum += number;
    }
    return sum;
}

private double calculateAverage(List<Integer> numbers, int sum) {
    return sum / (double) numbers.size();
}

private int findMax(List<Integer> numbers) {
    int max = Integer.MIN_VALUE;
    for (int number : numbers) {
        if (number > max) {
            max = number;
        }
    }
    return max;
}

private int findMin(List<Integer> numbers) {
    int min = Integer.MAX_VALUE;
    for (int number : numbers) {
        if (number < min) {
            min = number;
        }
    }
    return min;
}

private void printStatistics(int sum, double average, int max, int min) {
    System.out.println("Sum: " + sum);
    System.out.println("Average: " + average);
