```java
public class OrderProcessor {

    public void processOrder(Order order) {
        validateOrder(order);
        double total = calculateTotal(order);
        total = applyDiscount(order, total);
        confirmOrder(order);
        logOrderProcessing(order);
    }

    private void validateOrder(Order order) {
        if (order == null || order.getItems().isEmpty()) {
            throw new IllegalArgumentException("Order cannot be null or empty");
        }
    }

    private double calculateTotal(Order order) {
        double total = 0;
        for (Item item : order.getItems()) {
            total += item.getPrice() * item.getQuantity();
        }
        return total;
    }

    private double applyDiscount(Order order, double total) {
        if (order.hasDiscount()) {
            total -= order.getDiscount().apply(total);
        }
        return total;
    }

    private void confirmOrder(Order order) {
        order.setStatus("Confirmed");
    }

    private void logOrderProcessing(Order order) {
        System.out.println("Order processed: " + order.getId());
    }
}
