class Report {
  public String generateReport() {
    StringBuilder report = new StringBuilder();
    appendHeader(report);
    appendItems(report);
    appendFooter(report);
    return report.toString();
  }

  private void appendHeader(StringBuilder report) {
    report.append("Report Header\n");
    report.append("================\n");
  }

  private void appendItems(StringBuilder report) {
    for (Item item : getItems()) {
      report.append(item.getDescription());
      report.append(" : ");
      report.append(item.getPrice());
