}

class DomesticShipping extends ShippingStrategy {
  @Override
  public double calculateCost(double weight) {
    return weight <= 5 ? 5.0 : 10.0;
  }
}

class InternationalShipping extends ShippingStrategy {
  @Override
  public double calculateCost(double weight) {
    return weight <= 5 ? 15.0 : 25.0;
  }
}

