abstract class ReportView {
  protected Report report;
  protected ReportView(Report report) {
    this.report = report;
  }
  protected abstract String formatTitle();
  protected abstract String formatSummary();
  protected abstract String formatDetails();
  protected abstract String formatAuthor();
  protected abstract String formatDate();

  public String view() {
