  public ReportJson(Report report) { super(report); }
  @Override protected String formatTitle() { return "{ \"title\": \"" + report.getTitle() + "\", "; }
  @Override protected String formatSummary() { return "\"summary\": \"" + report.getSummary() + "\", "; }
  @Override protected String formatDetails() { return "\"details\": \"" + report.getDetails() + "\", "; }
  @Override protected String formatAuthor() { return "\"author\": \"" + report.getAuthor() + "\", "; }
  @Override protected String formatDate() { return "\"date\": \"" + report.getDate() + "\" }"; }
}

class ReportXml extends ReportView {
  public ReportXml(Report report) { super(report); }
  @Override protected String formatTitle() { return "<report><title>" + report.getTitle() + "</title>"; }
  @Override protected String formatSummary() { return "<summary>" + report.getSummary() + "</summary>"; }
  @Override protected String formatDetails() { return "<details>" + report.getDetails() + "</details>"; }
  @Override protected String formatAuthor() { return "<author>" + report.getAuthor() + "</author>"; }
  @Override protected String formatDate() { return "<date>" + report.getDate() + "</date></report>"; }
}
```

