```java
class DataProcessor {

  public void process(String data) {
    if (validateData(data)) {
      String[] items = data.split(",");
      for (String item : items) {
        processItem(item);
      }
    }
  }

  private boolean validateData(String data) {
    return data != null && !data.isEmpty();
  }

