class TemperatureConverter extends Frame implements Observer {
  java.awt.TextField celsiusField;
  java.awt.TextField fahrenheitField;
  private TemperatureModel model;

  public TemperatureConverter() {
    celsiusField = new java.awt.TextField();
    fahrenheitField = new java.awt.TextField();
    SymFocus focusListener = new SymFocus();
    celsiusField.addFocusListener(focusListener);
    fahrenheitField.addFocusListener(focusListener);
    model = new TemperatureModel();
    model.addObserver(this);
    update(model, null);
  }

  public void update(Observable observed, Object arg) {
    celsiusField.setText(model.getCelsius());
    fahrenheitField.setText(model.getFahrenheit());
  }

  class SymFocus extends java.awt.event.FocusAdapter {
    public void focusLost(java.awt.event.FocusEvent event) {
      Object object = event.getSource();
      if (object == celsiusField) {
        model.setCelsius(celsiusField.getText());
      } else if (object == fahrenheitField) {
        model.setFahrenheit(fahrenheitField.getText());
      }
    }
  }
}

class TemperatureModel extends Observable {
  private String celsius = "0";
  private String fahrenheit = "32";

  String getCelsius() { return celsius; }
  void setCelsius(String celsius) {
    this.celsius = celsius;
    calculateFahrenheit();
    setChanged();
    notifyObservers();
  }

  String getFahrenheit() { return fahrenheit; }
  void setFahrenheit(String fahrenheit) {
    this.fahrenheit = fahrenheit;
    calculateCelsius();
    setChanged();
    notifyObservers();
  }

  void calculateFahrenheit() {
    try {
      double celsiusValue = Double.parseDouble(celsius);
      fahrenheit = String.valueOf((celsiusValue * 9/5) + 32);
    } catch (NumberFormatException e) {
      throw new RuntimeException("Unexpected Number Format Error");
    }
  }

  void calculateCelsius() {
    try {
      double fahrenheitValue = Double.parseDouble(fahrenheit);
      celsius = String.valueOf((fahrenheitValue - 32) * 5/9);
    } catch (NumberFormatException e) {
      throw new RuntimeException("Unexpected Number Format Error");
    }
  }
}
// Explanation: The original code exhibited a code smell due to direct manipulation of UI components within the business logic, violating the Single Responsibility Principle. By adopting the Observer pattern, the refactoring isolates the business logic in `TemperatureModel`, which handles temperature conversion and notifies the `TemperatureConverter` to update the UI. This separation of concerns enhances maintainability and adheres to best practices in software design.
