public class Calculator {
    public int add(int a, int b) {
        return a + b;
    }

    public int subtract(int a, int b) {
        return a - b;
    }

    public int multiply(int a, int b) {
        return a * b;
    }

    public int divide(int a, int b) {
        return safeDivide(a, b);
    }

    private int safeDivide(int a, int b) {
        if (b == 0) {
            throw new IllegalArgumentException("Division by zero is undefined");
        }
        return a / b;
    }

    public int addAndMultiply(int a, int b, int c) {
        return multiply(add(a, b), c);
    }

    public int subtractAndDivide(int a, int b, int c) {
        return safeDivide(subtract(a, b), c);
    }
}
