public int calculateTotalPrice(List<Item> items) {
    int total = 0;
    for (Item item : items) {
        total += calculateFinalPrice(item);
    }
    return total;
}

private int calculateFinalPrice(Item item) {
    int price = item.getPrice();
    int discount = calculateDiscount(price, item.isOnSale());
    return applyTax(price - discount);
}

private int calculateDiscount(int price, boolean onSale) {
    return onSale ? price * 20 / 100 : 0;
}

